P/RNBQKB1R b KQkq - 1 2", "winBefore": 60.782230092727296, "bestMoveSAN": "e5", "bestMoveUCI": "e7e5", "bestLineSANs": ["e5", "Nb3", "a5", "a4", "Bb4", "c3"], "cpWhiteAfter": -105, "classification": "best", "evalWhitePctAfter": 40.453161641669574}, {"ply": 4, "san": "f3", "uci": "f2f3", "color": "w", "isBest": false, "accuracy": 23.700490614199545, "fenAfter": "rnbqkbnr/ppp2ppp/8/3pp3/3N4/5P2/PPPPP1PP/RNBQKB1R b KQkq - 0 3", "winAfter": 8.683957548832154, "coachText": "Blunder, this loses significant material or the game. Nb3 was the engine's choice.", "fenBefore": "rnbqkbnr/ppp2ppp/8/3pp3/3N4/8/PPPPPPPP/RNBQKB1R w KQkq e6 0 3", "winBefore": 40.453161641669574, "bestMoveSAN": "Nb3", "bestMoveUCI": "d4b3", "bestLineSANs": ["Nb3", "Nf6", "g3", "Nc6", "Bg2", "a5"], "cpWhiteAfter": -639, "classification": "blunder", "evalWhitePctAfter": 8.683957548832154}, {"ply": 5, "san": "e4", "uci": "e5e4", "color": "b", "isBest": false, "accuracy": 29.437995633596703, "fenAfter": "rnbqkbnr/ppp2ppp/8/3p4/3Np3/5P2/PPPPP1PP/RNBQKB1R w KQkq - 0 4", "winAfter": 64.14742687583961, "coachText": "Missed a much stronger continuation. exd4 was the engine's choice.", "fenBefore": "rnbqkbnr/ppp2ppp/8/3pp3/3N4/5P2/PPPPP1PP/RNBQKB1R b KQkq - 0 3", "winBefore": 91.31604245116785, "bestMoveSAN": "exd4", "bestMoveUCI": "e5d4", "bestLineSANs": ["exd4", "c3", "c5", "e4", "Be7", "exd5"], "cpWhiteAfter": -158, "classification": "miss", "evalWhitePctAfter": 35.85257312416039}, {"ply": 6, "san": "h4", "uci": "h2h4", "color": "w", "isBest": false, "accuracy": 62.803708371804454, "fenAfter": "rnbqkbnr/ppp2ppp/8/3p4/3Np2P/5P2/PPPPP1P1/RNBQKB1R b KQkq h3 0 4", "winAfter": 25.233195253996428, "coachText": "A mistake that hands the opponent an edge. e3 was the engine's choice.", "fenBefore": "rnbqkbnr/ppp2ppp/8/3p4/3Np3/5P2/PPPPP1PP/RNBQKB1R w KQkq - 0 4", "winBefore": 35.85257312416039, "bestMoveSAN": "e3", "bestMoveUCI": "e2e3", "bestLineSANs": ["e3", "c5", "Bb5+", "Bd7", "Bxd7+", "Nxd7"], "cpWhiteAfter": -295, "classification": "mistake", "evalWhitePctAfter": 25.233195253996428}, {"ply": 7, "san": "Qxh4+", "uci": "d8h4", "color": "b", "isBest": false, "accuracy": 4.273099891057285, "fenAfter": "rnb1kbnr/ppp2ppp/8/3p4/3Np2q/5P2/PPPPP1P1/RNBQKB1R w KQkq - 0 5", "winAfter": 11.065605336229595, "coachText": "Missed a much stronger continuation. c5 was the engine's choice.", "fenBefore": "rnbqkbnr/ppp2ppp/8/3p4/3Np2P/5P2/PPPPP1P1/RNBQKB1R b KQkq h3 0 4", "winBefore": 74.76680474600357, "bestMoveSAN": "c5", "bestMoveUCI": "c7c5", "bestLineSANs": ["c5", "Nb3", "Be7", "Kf2", "exf3", "exf3"], "cpWhiteAfter": 566, "classification": "miss", "evalWhitePctAfter": 88.9343946637704}, {"ply": 8, "san": "g3", "uci": "g2g3", "color": "w", "isBest": false, "accuracy": 0, "fenAfter": "rnb1kbnr/ppp2ppp/8/3p4/3Np2q/5PP1/PPPPP3/RNBQKB1R b KQkq - 0 5", "winAfter": 0, "coachText": "Missed a much stronger continuation. Rxh4 was the engine's choice.", "fenBefore": "rnb1kbnr/ppp2ppp/8/3p4/3Np2q/5P2/PPPPP1P1/RNBQKB1R w KQkq - 0 5", "winBefore": 88.9343946637704, "bestMoveSAN": "Rxh4", "bestMoveUCI": "h1h4", "bestLineSANs": ["Rxh4", "Bd6", "Kf2", "g5", "Rh1", "h5"], "cpWhiteAfter": -9999, "classification": "miss", "mateWhiteAfter": -1, "evalWhitePctAfter": 0}, {"ply": 9, "san": "Qxg3#", "uci": "h4g3", "color": "b", "isBest": true, "accuracy": 100, "fenAfter": "rnb1kbnr/ppp2ppp/8/3p4/3Np3/5Pq1/PPPPP3/RNBQKB1R w KQkq - 0 6", "winAfter": 100, "coachText": "Best move.", "fenBefore": "rnb1kbnr/ppp2ppp/8/3p4/3Np2q/5PP1/PPPPP3/RNBQKB1R b KQkq - 0 5", "winBefore": 100, "bestMoveSAN": "Qxg3#", "bestMoveUCI": "h4g3", "bestLineSANs": ["Qxg3#"], "cpWhiteAfter": -10000, "classification": "best", "mateWhiteAfter": -1, "evalWhitePctAfter": 0}], "result": {"outcome": {"win": {"_0": "b"}}, "termination": "checkmate"}, "keyMoments": [2, 4, 5, 6, 7, 8, 9], "blackCounts": ["best", 3, "miss", 2], "blackRating": 380, "openingName": "Réti / King's Indian Attack", "whiteCounts": ["mistake", 2, "miss", 1, "blunder", 1, "book", 1], "whiteRating": 360, "blackAccuracy": 19.376417820872426, "whiteAccuracy": 17.053256756485904, "positionBestUCI": ["e2e4", "d7d5", "d2d4", "e7e5", "d4b3", "e5d4", "e2e3", "c7c5", "h1h4", "h4g3", null], "engineUnavailable": false, "evalWhiteCPSeries": [41, 21, 17, -119, -105, -639, -158, -295, 566, -9999, -10000], "evalWhitePctSeries": [53.76698043044984, 51.93212942024339, 51.56437324214209, 39.217769907272704, 40.453161641669574, 8.683957548832154, 35.85257312416039, 25.233195253996428, 88.9343946637704, 0, 0]}"#
        let wrapped = "{\"review\":" + reviewJSON + "}"
        let resp = try JSONDecoder().decode(GameReviewResponse.self, from: Data(wrapped.utf8))
        XCTAssertNotNil(resp.review, "the real stored review must decode")
        XCTAssertEqual(resp.review?.moves.count, 10)
        XCTAssertEqual(resp.review?.result?.outcome, .win(.black))
        XCTAssertEqual(resp.review?.result?.termination, .checkmate)
        XCTAssertEqual(resp.review?.whiteCounts[.mistake], 2)
